"use client";

import { type PopoverProps, PopoverRoot } from "./popover";
import { PopoverContent, type PopoverContentProps } from "./popover-content";
import type { PopoverPopupRole, PopoverTriggerMode } from "./popover-context";
import {
  PopoverTrigger,
  type PopoverTriggerProps,
  type PopoverTriggerRenderProps,
} from "./popover-trigger";

const Popover = Object.assign(PopoverRoot, {
  Trigger: PopoverTrigger,
  Content: PopoverContent,
});

export { Popover, type PopoverProps };
export {
  PopoverTrigger,
  PopoverContent,
  type PopoverPopupRole,
  type PopoverTriggerMode,
  type PopoverTriggerProps,
  type PopoverTriggerRenderProps,
  type PopoverContentProps,
};

"use client";

import { Children, isValidElement, type ReactNode, useId, useRef } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { PopoverContent } from "./popover-content";
import {
  PopoverContext,
  type PopoverContextValue,
  type PopoverPopupRole,
  type PopoverTriggerMode,
} from "./popover-context";
import { usePopoverBehavior } from "./use-behavior";

/** Props for popover. */
export interface PopoverProps {
  /** Popover.Trigger and Popover.Content subparts. */
  children: ReactNode;
  /** Controlled open state. Pair with onOpenChange. */
  open?: boolean;
  /** Initial open state for uncontrolled mode. */
  defaultOpen?: boolean;
  /** Fired when the open state changes. */
  onOpenChange?: (open: boolean) => void;
  /** Click toggles; hover delays pointer-open, keyboard focus opens immediately, and leave closes. */
  triggerMode?: PopoverTriggerMode;
  /** Overrides the auto-detected aria-haspopup value applied to the trigger. */
  popupRole?: PopoverPopupRole;
  /** When false, the popover never opens and trigger handlers are no-ops. */
  enabled?: boolean;
  /** Hover mode only. Delay before opening after pointer enter; keyboard focus opens immediately. */
  delayMs?: number;
  /** Delay before closing after hover/focus leaves the trigger or content. */
  closeDelayMs?: number;
}

/** Root - manages open state, trigger mode (click/hover), delay. */
export function PopoverRoot({
  children,
  open: controlledOpen,
  defaultOpen = false,
  onOpenChange: onOpenChangeProp,
  triggerMode = "click",
  popupRole: popupRoleProp,
  enabled = true,
  delayMs = 500,
  closeDelayMs: closeDelayMsProp,
}: PopoverProps) {
  const closeDelayMs = closeDelayMsProp ?? (triggerMode === "hover" ? 150 : 0);
  const triggerRef = useRef<HTMLElement | null>(null);
  const popoverId = useId();

  const [openState, setOpenState] = useControllableState<boolean>({
    value: controlledOpen,
    defaultValue: defaultOpen,
    onChange: onOpenChangeProp,
  });

  const behavior = usePopoverBehavior({
    open: openState,
    onOpenChange: setOpenState,
    enabled,
    triggerMode,
    delayMs,
    closeDelayMs,
    triggerRef,
  });
  const contentPopupRole = triggerMode === "click" ? getContentPopupRole(children) : undefined;

  // usePopoverBehavior returns fresh handlers every render (they close over the
  // current open/enabled state), so a useMemo here could never hit — building
  // the context value inline is honest about that.
  const ctx: PopoverContextValue = {
    open: openState && enabled,
    triggerRef,
    popoverId,
    triggerMode,
    popupRole: popupRoleProp ?? contentPopupRole,
    onOpenChange: setOpenState,
    onTriggerEnter: behavior.onTriggerEnter,
    onTriggerFocus: behavior.onTriggerFocus,
    onTriggerLeave: behavior.onTriggerLeave,
    onTriggerBlur: behavior.onTriggerBlur,
    onTriggerClick: behavior.onTriggerClick,
    onTriggerPointerDown: behavior.onTriggerPointerDown,
    markDismissed: behavior.markDismissed,
    onContentEnter: behavior.onContentEnter,
    onContentLeave: behavior.onContentLeave,
    enabled,
  };

  return <PopoverContext value={ctx}>{children}</PopoverContext>;
}

function getContentPopupRole(children: ReactNode): PopoverPopupRole | undefined {
  for (const child of Children.toArray(children)) {
    if (!isValidElement<{ role?: PopoverPopupRole; children?: ReactNode }>(child)) continue;
    if (child.type === PopoverContent) return child.props.role;
    const nestedRole = getContentPopupRole(child.props.children);
    if (nestedRole !== undefined) return nestedRole;
  }
  return undefined;
}

"use client";

import { createContext, type RefObject, useContext } from "react";

export type PopoverTriggerMode = "click" | "hover";
export type PopoverPopupRole = "dialog" | "menu" | "listbox" | "tree" | "grid";

/** Context value shared by popover. */
export interface PopoverContextValue {
  /** Controlled open state. Pair with onOpenChange. */
  open: boolean;
  /** Ref for the trigger element. */
  triggerRef: RefObject<HTMLElement | null>;
  /** DOM id for popover. */
  popoverId: string;
  /** Click toggles; hover delays pointer-open, keyboard focus opens immediately, and leave closes. */
  triggerMode: PopoverTriggerMode;
  /** Overrides the auto-detected aria-haspopup value applied to the trigger. */
  popupRole?: PopoverPopupRole;
  /** Fired when the open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Called when trigger enter occurs. */
  onTriggerEnter: () => void;
  /** Called when trigger focus occurs. */
  onTriggerFocus: () => void;
  /** Called when pointer leaves the trigger. */
  onTriggerLeave: () => void;
  /** Called when focus leaves the trigger. */
  onTriggerBlur: () => void;
  /** Called when trigger click occurs. */
  onTriggerClick: () => void;
  /** Called when trigger pointer down occurs. */
  onTriggerPointerDown: () => void;
  /** Suppresses immediate focus-open after dismissal. */
  markDismissed: () => void;
  /** Called when content enter occurs. */
  onContentEnter: () => void;
  /** Called when content leave occurs. */
  onContentLeave: () => void;
  /** When false, the popover never opens and trigger handlers are no-ops. */
  enabled: boolean;
}

/** React context backing popover. */
export const PopoverContext = createContext<PopoverContextValue | undefined>(undefined);

/** Reads the popover context. */
export function usePopoverContext() {
  const ctx = useContext(PopoverContext);
  if (ctx === undefined) throw new Error("Popover parts must be used within <Popover>");
  return ctx;
}

"use client";

import {
  type ComponentPropsWithRef,
  cloneElement,
  type FocusEventHandler,
  isValidElement,
  type KeyboardEventHandler,
  type MouseEventHandler,
  type PointerEventHandler,
  type ReactElement,
  type ReactNode,
  type Ref,
  type RefCallback,
  useEffect,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { mergeIds } from "@/lib/aria";
import { cn } from "@/lib/utils";
import { isNativeInteractiveElement, mergeHandlers } from "../shared/trigger-interop";
import { type PopoverPopupRole, usePopoverContext } from "./popover-context";

/** Props for popover trigger render. */
export interface PopoverTriggerRenderProps {
  /** Ref forwarded to the underlying element. */
  ref: RefCallback<HTMLElement>;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** ARIA role applied to the rendered element. */
  role?: "button";
  /** ARIA expanded state forwarded to the rendered element. */
  "aria-expanded"?: boolean;
  /** ARIA popup type forwarded to the rendered element. */
  "aria-haspopup"?: PopoverPopupRole;
  /** ID of the element controlled by the rendered element. */
  "aria-controls"?: string;
  /** ID of the element that describes this component. */
  "aria-describedby"?: string;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** ARIA hidden state forwarded to the rendered element. */
  "aria-hidden"?: boolean;
  /** Called when click occurs. */
  onClick?: MouseEventHandler<HTMLElement>;
  /** Called when pointer down occurs. */
  onPointerDown?: PointerEventHandler<HTMLElement>;
  /** Called when mouse enter occurs. */
  onMouseEnter?: MouseEventHandler<HTMLElement>;
  /** Called when mouse leave occurs. */
  onMouseLeave?: MouseEventHandler<HTMLElement>;
  /** Called when focus occurs. */
  onFocus?: FocusEventHandler<HTMLElement>;
  /** Called when blur occurs. */
  onBlur?: FocusEventHandler<HTMLElement>;
  /** Called when key down occurs. */
  onKeyDown?: KeyboardEventHandler<HTMLElement>;
  /** Tab index applied to the rendered element. */
  tabIndex?: number;
}

/** Props for popover trigger. */
export interface PopoverTriggerProps {
  /**
   * Trigger element. Pass a single element (cloned with merged ARIA/handlers), text (wrapped in
   * <button>), or a render function for full control.
   */
  children: ReactNode | ((props: PopoverTriggerRenderProps) => ReactNode);
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLElement>;
}

interface HoverTriggerElementProps {
  ref?: Ref<HTMLElement>;
  className?: string;
  type?: string;
  role?: string;
  tabIndex?: number;
  children?: ReactNode;
  "aria-expanded"?: boolean;
  "aria-haspopup"?: PopoverPopupRole;
  "aria-controls"?: string;
  "aria-describedby"?: string;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  "aria-hidden"?: boolean;
  id?: string;
  onClick?: MouseEventHandler<HTMLElement>;
  onPointerDown?: PointerEventHandler<HTMLElement>;
  onMouseEnter?: MouseEventHandler<HTMLElement>;
  onMouseLeave?: MouseEventHandler<HTMLElement>;
  onFocus?: FocusEventHandler<HTMLElement>;
  onBlur?: FocusEventHandler<HTMLElement>;
  onKeyDown?: KeyboardEventHandler<HTMLElement>;
  disabled?: boolean;
}

function usesButtonLikeHoverSemantics(element: ReactElement<HoverTriggerElementProps>): boolean {
  return isNativeInteractiveElement(element) || element.props.role === "button";
}

/** Element that activates the popover (click or hover) */
export function PopoverTrigger({ children, className, ref }: PopoverTriggerProps) {
  const {
    triggerRef,
    popoverId,
    open,
    triggerMode,
    onOpenChange,
    onTriggerEnter,
    onTriggerFocus,
    onTriggerLeave,
    onTriggerBlur,
    onTriggerClick,
    onTriggerPointerDown,
    markDismissed,
    enabled,
    popupRole,
  } = usePopoverContext();

  const childRef = isValidElement<HoverTriggerElementProps>(children)
    ? children.props.ref
    : undefined;
  const composedRef = useComposedRefs(triggerRef, ref, childRef);
  const isClick = triggerMode === "click";
  const isRenderProp = typeof children === "function";
  const hoverClassName = isRenderProp ? className : cn("inline-flex", className);

  // Tap/focus-opened hover popovers have no hover-leave; dismiss on any
  // pointerdown outside the trigger and portaled content.
  useEffect(() => {
    if (isClick || !open || !enabled) return;
    const trigger = triggerRef.current;
    if (!trigger) return;
    const handlePointerDown = (event: PointerEvent) => {
      const View = trigger.ownerDocument.defaultView;
      if (!View || !(event.target instanceof View.Node)) return;
      if (trigger.contains(event.target)) return;
      const content = trigger.ownerDocument.getElementById(popoverId);
      if (content?.contains(event.target)) return;
      markDismissed();
      onOpenChange(false);
    };
    const doc = trigger.ownerDocument;
    doc.addEventListener("pointerdown", handlePointerDown, { capture: true });
    return () => doc.removeEventListener("pointerdown", handlePointerDown, { capture: true });
  }, [enabled, isClick, markDismissed, onOpenChange, open, popoverId, triggerRef]);

  const handleHoverClick = () => {
    if (!enabled) return;
    if (open) markDismissed();
    onOpenChange(!open);
  };

  // Touch has no hover, so the passive <span> wrapper needs an explicit toggle.
  // Only touch toggles here; mouse/pen go through onClick/onMouseEnter to avoid
  // double-firing.
  const handlePassiveTouchPointerDown: PointerEventHandler<HTMLElement> = (event) => {
    if (!enabled) return;
    onTriggerPointerDown();
    if (event.pointerType !== "touch") return;
    if (open) markDismissed();
    onOpenChange(!open);
  };

  const handleHoverPointerDown: PointerEventHandler<HTMLElement> = () => {
    // Suppress the focus-open that follows a pointer so the click toggle owns it.
    onTriggerPointerDown();
  };

  const handleHoverKeyDown: KeyboardEventHandler<HTMLElement> = (event) => {
    if (!enabled) return;
    if (event.key !== "Enter" && event.key !== " ") return;
    event.preventDefault();
    if (open) markDismissed();
    onOpenChange(!open);
  };

  const clickTriggerProps: PopoverTriggerRenderProps = {
    ref: composedRef,
    className,
    "aria-expanded": open,
    "aria-haspopup": popupRole,
    "aria-controls": open ? popoverId : undefined,
    onClick: onTriggerClick,
  };
  const interactiveHoverTriggerProps: PopoverTriggerRenderProps = {
    ref: composedRef,
    role: "button",
    className: hoverClassName,
    "aria-describedby": open ? popoverId : undefined,
    onPointerDown: handleHoverPointerDown,
    onMouseEnter: onTriggerEnter,
    onMouseLeave: onTriggerLeave,
    onFocus: onTriggerFocus,
    onBlur: onTriggerBlur,
    onClick: handleHoverClick,
    onKeyDown: handleHoverKeyDown,
    tabIndex: enabled ? 0 : undefined,
  };
  const passiveHoverTriggerProps: PopoverTriggerRenderProps = {
    ref: composedRef,
    className: hoverClassName,
    "aria-describedby": open ? popoverId : undefined,
    onPointerDown: handlePassiveTouchPointerDown,
    onMouseEnter: onTriggerEnter,
    onMouseLeave: onTriggerLeave,
    onFocus: onTriggerFocus,
    onBlur: onTriggerBlur,
  };

  const triggerProps = isClick ? clickTriggerProps : interactiveHoverTriggerProps;

  const passiveTriggerProps = isClick ? clickTriggerProps : passiveHoverTriggerProps;

  if (typeof children === "function") return <>{children(triggerProps)}</>;

  if (isValidElement<HoverTriggerElementProps>(children)) {
    const child = children as ReactElement<HoverTriggerElementProps>;
    const isNativeInteractive = isNativeInteractiveElement(child);
    const isButtonLikeHover = usesButtonLikeHoverSemantics(child);
    const buttonType = child.type === "button" ? { type: child.props.type ?? "button" } : {};

    if (isClick && isNativeInteractive) {
      return cloneElement(child, {
        ...buttonType,
        ref: composedRef,
        className: cn(child.props.className, className),
        "aria-expanded": triggerProps["aria-expanded"],
        "aria-haspopup": triggerProps["aria-haspopup"],
        "aria-controls": triggerProps["aria-controls"],
        onClick: mergeHandlers(child.props.onClick, triggerProps.onClick, true),
      });
    }

    if (isClick) {
      const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
      return (
        <button type="button" {...buttonProps}>
          {children}
        </button>
      );
    }

    // Any non-natively-focusable hover trigger needs a tab stop so keyboard/SR
    // users can focus it and reveal the tooltip (WCAG 2.1.1/1.4.13) — not only
    // role="button" children. Native interactive elements already focus.
    const needsTabIndex = enabled && child.props.tabIndex === undefined && !isNativeInteractive;
    const isDisabledNative = triggerMode === "hover" && isNativeInteractive && child.props.disabled;

    if (isDisabledNative) {
      const spanProps = passiveTriggerProps satisfies ComponentPropsWithRef<"span">;
      const childId = child.props.id ?? `${popoverId}-trigger`;
      return (
        // biome-ignore lint/a11y/useAriaPropsSupportedByRole: the neutral wrapper is the only focus path for a disabled native control and receives its name from that control.
        <span
          {...spanProps}
          aria-label={child.props["aria-label"]}
          aria-labelledby={
            child.props["aria-label"] ? undefined : (child.props["aria-labelledby"] ?? childId)
          }
          tabIndex={enabled ? 0 : undefined}
        >
          {cloneElement(child, {
            id: childId,
            className: cn(child.props.className, className),
            "aria-describedby": mergeIds(
              child.props["aria-describedby"],
              passiveTriggerProps["aria-describedby"],
            ),
          })}
        </span>
      );
    }

    const hoverProps = isButtonLikeHover ? triggerProps : passiveTriggerProps;

    return cloneElement(child, {
      ref: composedRef,
      className: cn(child.props.className, className),
      role: child.props.role ?? (isClick || isNativeInteractive ? undefined : hoverProps.role),
      "aria-describedby": mergeIds(child.props["aria-describedby"], hoverProps["aria-describedby"]),
      onClick: mergeHandlers(child.props.onClick, hoverProps.onClick, true),
      onPointerDown: mergeHandlers(child.props.onPointerDown, hoverProps.onPointerDown, true),
      onMouseEnter: mergeHandlers(child.props.onMouseEnter, hoverProps.onMouseEnter),
      onMouseLeave: mergeHandlers(child.props.onMouseLeave, hoverProps.onMouseLeave),
      onFocus: mergeHandlers(child.props.onFocus, hoverProps.onFocus),
      onBlur: mergeHandlers(child.props.onBlur, hoverProps.onBlur),
      onKeyDown: isNativeInteractive
        ? child.props.onKeyDown
        : mergeHandlers(child.props.onKeyDown, hoverProps.onKeyDown, true),
      tabIndex: needsTabIndex ? 0 : child.props.tabIndex,
    });
  }

  if (isClick) {
    const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
    return (
      <button type="button" {...buttonProps}>
        {children}
      </button>
    );
  }

  const spanProps = passiveTriggerProps satisfies ComponentPropsWithRef<"span">;
  // Plain non-interactive children (e.g. a tooltip on text) need a tab stop so
  // keyboard/SR users can focus the trigger and reveal the tooltip.
  return (
    <span {...spanProps} tabIndex={enabled ? 0 : undefined}>
      {children}
    </span>
  );
}

"use client";

import {
  type ComponentPropsWithoutRef,
  type FocusEvent,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  type Ref,
  type RefObject,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import type { FloatingAlign, FloatingSide } from "@/hooks/use-floating-position";
import { useEscapeKey, useOutsideClick } from "@/hooks/use-outside-click";
import { FloatingPanel, useFloatingPanelContext } from "../floating-panel";
import { useAriaLinkedPortalContainer } from "../shared/portal";
import { type PopoverPopupRole, usePopoverContext } from "./popover-context";
import { useAutoFocus } from "./use-auto-focus";

const FALLBACK_POPOVER_DIALOG_LABEL = "Popover";

function isFocusInDescendantPopup(
  next: Node,
  content: HTMLElement,
  trigger: HTMLElement,
  ownerDocument: Document,
): boolean {
  const View = ownerDocument.defaultView;
  if (!View || !(next instanceof View.Element)) return false;
  const controlledIds = new Set<string>();
  for (const controller of ownerDocument.querySelectorAll<HTMLElement>("[aria-controls]")) {
    if (!content.contains(controller) && !trigger.contains(controller)) continue;
    const ids = controller.getAttribute("aria-controls")?.split(/\s+/) ?? [];
    for (const id of ids) controlledIds.add(id);
  }

  let current: Element | null = next;
  while (current) {
    if (current.id && controlledIds.has(current.id)) return true;
    current = current.parentElement;
  }
  return false;
}

/** Props for popover content. */
export interface PopoverContentProps
  extends Omit<ComponentPropsWithoutRef<"div">, "children" | "id" | "role" | "style"> {
  /** Popover body content. */
  children: ReactNode;
  /**
   * Popup role. Ignored when the popover opens on hover: hover popovers are always
   * `role="tooltip"`. For click/focus popovers this role is used as-is (e.g. `"dialog"` or
   * `"menu"`); a `"dialog"` popup also gains a fallback accessible name and is focusable.
   * Switch `triggerMode` off hover to take control of the role.
   */
  role?: PopoverPopupRole;
  /** Preferred side relative to the trigger. */
  side?: FloatingSide;
  /** Alignment along the chosen side. */
  align?: FloatingAlign;
  /** Pixel gap from the trigger along the side axis. */
  sideOffset?: number;
  /** Pixel offset along the alignment axis. */
  alignOffset?: number;
  /** Flips to the opposite side, then cross-axis sides, then shifts within the viewport. */
  avoidCollisions?: boolean;
  /** Minimum gap between the content and the viewport edge during collision avoidance. */
  collisionPadding?: number;
  /**
   * Dialog and menu roles only. When true, focuses the first focusable child on open (or the
   * content itself for role="dialog" without a focusable child).
   */
  autoFocus?: boolean;
  portalContainer?: Element | null;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** Stable slot marker for styling and tests. */
  "data-slot"?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Portal-rendered positioned content with collision avoidance. */
export function PopoverContent({
  children,
  side = "bottom",
  align = "center",
  sideOffset = 6,
  alignOffset = 0,
  avoidCollisions = true,
  collisionPadding = 8,
  portalContainer,
  className,
  role,
  autoFocus = true,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  tabIndex,
  ref,
  onMouseEnter,
  onMouseLeave,
  onFocusCapture,
  onBlurCapture,
  onKeyDown,
  "data-slot": dataSlot = "popover-content",
  ...rest
}: PopoverContentProps) {
  const {
    open,
    triggerRef,
    popoverId,
    triggerMode,
    onOpenChange,
    onContentEnter,
    onContentLeave,
    markDismissed,
  } = usePopoverContext();
  const contentRef = useRef<HTMLDivElement>(null);
  const wasOpenRef = useRef(open);
  const restoreFocusAfterCloseRef = useRef(false);
  const dismissRequestedRef = useRef(false);
  const dismissResetRef = useRef<{ timer: number; view: Window } | null>(null);
  const pointerFocusTransferRef = useRef(false);
  const pointerResetRef = useRef<{ timer: number; view: Window } | null>(null);
  const composedRef = useComposedRefs(contentRef, ref);

  const isHover = triggerMode === "hover";
  const isClick = triggerMode === "click";
  const contentRole = isHover ? "tooltip" : role;
  const isDialog = contentRole === "dialog";
  const isMenu = contentRole === "menu";
  const resolvedAriaLabel =
    ariaLabel ?? (isDialog && !ariaLabelledBy ? FALLBACK_POPOVER_DIALOG_LABEL : undefined);
  const resolvedPortalContainer = useAriaLinkedPortalContainer(
    portalContainer,
    triggerRef,
    "Popover",
  );

  const requestClose = useCallback(
    (restoreFocus: boolean) => {
      if (dismissRequestedRef.current) return;
      dismissRequestedRef.current = true;
      const view =
        triggerRef.current?.ownerDocument.defaultView ??
        contentRef.current?.ownerDocument.defaultView;
      if (view) {
        const timer = view.setTimeout(() => {
          dismissResetRef.current = null;
          dismissRequestedRef.current = false;
        }, 0);
        dismissResetRef.current = { timer, view };
      } else {
        dismissRequestedRef.current = false;
      }
      markDismissed();
      onOpenChange(false);
      if (restoreFocus) triggerRef.current?.focus();
    },
    [markDismissed, onOpenChange, triggerRef],
  );

  useEffect(
    () => () => {
      const pendingReset = dismissResetRef.current;
      if (pendingReset) pendingReset.view.clearTimeout(pendingReset.timer);
      const pendingPointerReset = pointerResetRef.current;
      if (pendingPointerReset) {
        pendingPointerReset.view.clearTimeout(pendingPointerReset.timer);
      }
    },
    [],
  );

  const isFocusWithinPopover = () => {
    const content = contentRef.current;
    const trigger = triggerRef.current;
    const ownerDocument = content?.ownerDocument ?? trigger?.ownerDocument;
    const activeElement = ownerDocument?.activeElement;
    if (!activeElement) return false;
    return !!content?.contains(activeElement) || !!trigger?.contains(activeElement);
  };

  const handleExitComplete = () => {
    if (!restoreFocusAfterCloseRef.current) return;
    const trigger = triggerRef.current;
    const ownerDocument = trigger?.ownerDocument ?? contentRef.current?.ownerDocument;
    const activeElement = ownerDocument?.activeElement;
    if (activeElement && activeElement !== ownerDocument?.body) {
      if (trigger?.contains(activeElement)) restoreFocusAfterCloseRef.current = false;
      return;
    }
    trigger?.focus();
    restoreFocusAfterCloseRef.current = false;
  };

  useLayoutEffect(() => {
    const wasOpen = wasOpenRef.current;
    wasOpenRef.current = open;
    if (!wasOpen || open) return;
    const content = contentRef.current;
    const trigger = triggerRef.current;
    const ownerDocument = content?.ownerDocument ?? trigger?.ownerDocument;
    const activeElement = ownerDocument?.activeElement;
    const focusWithinPopover =
      !!activeElement && (!!content?.contains(activeElement) || !!trigger?.contains(activeElement));
    restoreFocusAfterCloseRef.current = focusWithinPopover;
    if (focusWithinPopover) {
      trigger?.focus();
      restoreFocusAfterCloseRef.current = false;
    }
  }, [open, triggerRef]);

  // useOutsideClick/useEscapeKey read excludeRefs/options through internal refs,
  // so inline arrays/objects here no longer re-register the overlay-stack entry.
  useOutsideClick(
    contentRef,
    () => {
      requestClose(false);
    },
    open && isClick,
    [triggerRef],
  );

  useEscapeKey(
    (e) => {
      const shouldRestoreFocus = isFocusWithinPopover();
      e.preventDefault();
      if (shouldRestoreFocus) {
        e.stopPropagation();
      }
      requestClose(shouldRestoreFocus);
    },
    open,
    { ref: contentRef, excludeRefs: [triggerRef] },
  );

  useEffect(() => {
    if (!open || !isClick) return;
    const trigger = triggerRef.current;
    const content = contentRef.current;
    const ownerDocument = trigger?.ownerDocument ?? content?.ownerDocument;
    if (!ownerDocument || !trigger || !content) return;

    const handleFocusOut = (event: globalThis.FocusEvent) => {
      const path = typeof event.composedPath === "function" ? event.composedPath() : [];
      const target = event.target;
      const View = ownerDocument.defaultView;
      const startedInPair =
        path.includes(trigger) ||
        path.includes(content) ||
        (!!View &&
          target instanceof View.Node &&
          (trigger.contains(target) || content.contains(target)));
      if (!startedInPair) return;
      if (pointerFocusTransferRef.current) return;

      const next = event.relatedTarget;
      if (View && next instanceof View.Node) {
        if (content.contains(next) || trigger.contains(next)) return;
        if (isFocusInDescendantPopup(next, content, trigger, ownerDocument)) return;
      }
      requestClose(false);
    };

    const handlePointerStart = () => {
      const pendingReset = pointerResetRef.current;
      if (pendingReset) pendingReset.view.clearTimeout(pendingReset.timer);
      pointerFocusTransferRef.current = true;
      const view = ownerDocument.defaultView;
      if (!view) {
        pointerFocusTransferRef.current = false;
        return;
      }
      const timer = view.setTimeout(() => {
        pointerResetRef.current = null;
        pointerFocusTransferRef.current = false;
      }, 0);
      pointerResetRef.current = { timer, view };
    };

    ownerDocument.addEventListener("focusout", handleFocusOut);
    ownerDocument.addEventListener("pointerdown", handlePointerStart, true);
    ownerDocument.addEventListener("mousedown", handlePointerStart, true);
    ownerDocument.addEventListener("touchstart", handlePointerStart, true);
    return () => {
      ownerDocument.removeEventListener("focusout", handleFocusOut);
      ownerDocument.removeEventListener("pointerdown", handlePointerStart, true);
      ownerDocument.removeEventListener("mousedown", handlePointerStart, true);
      ownerDocument.removeEventListener("touchstart", handlePointerStart, true);
    };
  }, [open, isClick, requestClose, triggerRef]);

  const handleMouseEnter = (e: MouseEvent<HTMLDivElement>) => {
    onMouseEnter?.(e);
    if (isHover) onContentEnter();
  };

  const handleMouseLeave = (e: MouseEvent<HTMLDivElement>) => {
    onMouseLeave?.(e);
    if (isHover) onContentLeave();
  };

  const handleFocusCapture = (e: FocusEvent<HTMLDivElement>) => {
    onFocusCapture?.(e);
    restoreFocusAfterCloseRef.current = true;
  };

  const handleBlurCapture = (e: FocusEvent<HTMLDivElement>) => {
    onBlurCapture?.(e);
    const next = e.relatedTarget;
    const content = contentRef.current;
    const trigger = triggerRef.current;
    const View = content?.ownerDocument.defaultView ?? trigger?.ownerDocument.defaultView;
    if (View && next instanceof View.Node && (content?.contains(next) || trigger?.contains(next))) {
      return;
    }
    restoreFocusAfterCloseRef.current = false;
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;

    if (e.key === "Escape") {
      const shouldRestoreFocus = isFocusWithinPopover();
      e.preventDefault();
      if (shouldRestoreFocus) {
        e.stopPropagation();
      }
      requestClose(shouldRestoreFocus);
    }
  };

  const shouldAutoFocus = open && (isDialog || isMenu) && autoFocus;

  return (
    <FloatingPanel
      {...rest}
      open={open}
      triggerRef={triggerRef}
      portalContainer={resolvedPortalContainer}
      side={side}
      align={align}
      sideOffset={sideOffset}
      alignOffset={alignOffset}
      avoidCollisions={avoidCollisions}
      collisionPadding={collisionPadding}
      onExitComplete={handleExitComplete}
      ref={composedRef}
      id={popoverId}
      role={contentRole}
      data-slot={dataSlot}
      aria-label={resolvedAriaLabel}
      aria-labelledby={ariaLabelledBy}
      tabIndex={tabIndex ?? (isDialog ? -1 : undefined)}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onFocusCapture={handleFocusCapture}
      onBlurCapture={handleBlurCapture}
      onKeyDown={handleKeyDown}
      className={className}
    >
      <PopoverAutoFocus
        contentRef={contentRef}
        enabled={shouldAutoFocus}
        fallbackToContainer={isDialog}
      />
      {children}
    </FloatingPanel>
  );
}

/** Props for popover auto focus. */
interface PopoverAutoFocusProps {
  /** Ref for the content element. */
  contentRef: RefObject<HTMLDivElement | null>;
  /** Whether autofocus runs when the popover is positioned. */
  enabled: boolean;
  fallbackToContainer: boolean;
}

function PopoverAutoFocus({ contentRef, enabled, fallbackToContainer }: PopoverAutoFocusProps) {
  const { positioned } = useFloatingPanelContext();
  useAutoFocus(contentRef, enabled && positioned, fallbackToContainer);
  return null;
}

"use client";

import { type RefObject, useEffect, useRef } from "react";
import type { PopoverTriggerMode } from "./popover-context";

export interface UsePopoverBehaviorOptions {
  /** Controlled open state. Pair with onOpenChange. */
  open: boolean;
  /** Fired when the open state changes. */
  onOpenChange: (next: boolean | ((prev: boolean) => boolean)) => void;
  /** When false, the popover never opens and trigger handlers are no-ops. */
  enabled?: boolean;
  /** Click toggles; hover opens on pointer/focus enter with a delay and closes on leave. */
  triggerMode?: PopoverTriggerMode;
  /** Hover mode only. Delay before opening on hover or focus. */
  delayMs?: number;
  /** Delay before closing after hover/focus leaves the trigger or content. */
  closeDelayMs?: number;
  /** Ref for the trigger element. */
  triggerRef?: RefObject<HTMLElement | null>;
}

export interface UsePopoverBehaviorReturn {
  /** Called when trigger enter occurs. */
  onTriggerEnter: () => void;
  /** Called when trigger focus occurs. */
  onTriggerFocus: () => void;
  /** Called when pointer leaves the trigger. */
  onTriggerLeave: () => void;
  /** Called when focus leaves the trigger. */
  onTriggerBlur: () => void;
  /** Called when trigger click occurs. */
  onTriggerClick: () => void;
  /** Called when trigger pointer down occurs. */
  onTriggerPointerDown: () => void;
  /** Suppresses immediate focus-open after dismissal. */
  markDismissed: () => void;
  /** Called when content enter occurs. */
  onContentEnter: () => void;
  /** Called when content leave occurs. */
  onContentLeave: () => void;
}

// Window after a pointer interaction or a dismissal during which keyboard-focus
// must NOT auto-open: a pointer focus is owned by the click/touch toggle, and an
// Escape/outside dismissal refocuses the trigger without intending to reopen.
const FOCUS_OPEN_SUPPRESS_MS = 250;

export function usePopoverBehavior({
  open,
  onOpenChange,
  enabled = true,
  triggerMode = "click",
  delayMs = 500,
  closeDelayMs = 0,
  triggerRef,
}: UsePopoverBehaviorOptions): UsePopoverBehaviorReturn {
  const openTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const suppressFocusOpenUntilRef = useRef(0);
  const triggerPointerInsideRef = useRef(false);
  const triggerFocusedRef = useRef(false);
  const contentPointerInsideRef = useRef(false);

  const clearTimers = () => {
    if (openTimerRef.current) {
      clearTimeout(openTimerRef.current);
      openTimerRef.current = null;
    }
    if (closeTimerRef.current) {
      clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
  };

  const onTriggerEnter = () => {
    if (!enabled || triggerMode !== "hover") return;
    triggerPointerInsideRef.current = true;
    clearTimers();
    if (delayMs <= 0) {
      onOpenChange(true);
      return;
    }
    openTimerRef.current = setTimeout(() => onOpenChange(true), delayMs);
  };

  // Keyboard focus opens immediately (no hover-intent delay) so a tabbing user
  // does not wait delayMs per stop; pointer enter keeps the delay above. A focus
  // that immediately follows a pointer interaction or a dismissal is suppressed
  // so it does not fight the click toggle or reopen after Escape/outside close.
  const onTriggerFocus = () => {
    if (!enabled || triggerMode !== "hover") return;
    triggerFocusedRef.current = true;
    if (Date.now() < suppressFocusOpenUntilRef.current) return;
    clearTimers();
    onOpenChange(true);
  };

  const onTriggerPointerDown = () => {
    suppressFocusOpenUntilRef.current = Date.now() + FOCUS_OPEN_SUPPRESS_MS;
  };

  const markDismissed = () => {
    clearTimers();
    suppressFocusOpenUntilRef.current = Date.now() + FOCUS_OPEN_SUPPRESS_MS;
  };

  const hasHoverOwner = () =>
    triggerPointerInsideRef.current || triggerFocusedRef.current || contentPointerInsideRef.current;

  const scheduleCloseIfUnowned = () => {
    if (!enabled || triggerMode !== "hover") return;
    if (hasHoverOwner()) return;
    clearTimers();
    if (closeDelayMs > 0) {
      closeTimerRef.current = setTimeout(() => {
        closeTimerRef.current = null;
        if (!hasHoverOwner()) onOpenChange(false);
      }, closeDelayMs);
    } else {
      onOpenChange(false);
    }
  };

  const onTriggerLeave = () => {
    triggerPointerInsideRef.current = false;
    scheduleCloseIfUnowned();
  };

  const onTriggerBlur = () => {
    triggerFocusedRef.current = false;
    scheduleCloseIfUnowned();
  };

  const onTriggerClick = () => {
    if (!enabled || triggerMode !== "click") return;
    onOpenChange((prev) => !prev);
  };

  const onContentEnter = () => {
    if (!enabled || triggerMode !== "hover") return;
    contentPointerInsideRef.current = true;
    clearTimers();
  };

  const onContentLeave = () => {
    contentPointerInsideRef.current = false;
    scheduleCloseIfUnowned();
  };

  // Unmount-only cleanup. Inline timer-clear avoids depending on a function identity.
  useEffect(() => {
    return () => {
      if (openTimerRef.current) clearTimeout(openTimerRef.current);
      if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
    };
  }, []);

  // DOM listener attach/detach: keep deps minimal so listeners only re-attach on real
  // state changes, not on every render.
  useEffect(() => {
    if (!open || triggerMode !== "hover") return;
    const close = () => {
      if (openTimerRef.current) clearTimeout(openTimerRef.current);
      if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
      onOpenChange(false);
    };
    const scrollOpts = { capture: true, passive: true } as const;
    const view = triggerRef?.current?.ownerDocument?.defaultView ?? window;
    view.addEventListener("scroll", close, scrollOpts);
    view.addEventListener("resize", close);
    return () => {
      view.removeEventListener("scroll", close, scrollOpts);
      view.removeEventListener("resize", close);
    };
  }, [onOpenChange, open, triggerMode, triggerRef]);

  useEffect(() => {
    if (enabled) return;
    if (openTimerRef.current) {
      clearTimeout(openTimerRef.current);
      openTimerRef.current = null;
    }
    if (closeTimerRef.current) {
      clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
    if (!open) return;
    onOpenChange(false);
  }, [enabled, open, onOpenChange]);

  useEffect(() => {
    if (enabled) return;
    triggerPointerInsideRef.current = false;
    triggerFocusedRef.current = false;
    contentPointerInsideRef.current = false;
  }, [enabled]);

  return {
    onTriggerEnter,
    onTriggerFocus,
    onTriggerLeave,
    onTriggerBlur,
    onTriggerClick,
    onTriggerPointerDown,
    markDismissed,
    onContentEnter,
    onContentLeave,
  };
}

"use client";

import { getFirstFocusableElement } from "@/hooks/utils/focusable";
import { type RefObject, useEffect } from "react";

/** Provides auto focus behavior. */
export function useAutoFocus(
  ref: RefObject<HTMLElement | null>,
  enabled: boolean,
  fallbackToContainer = true,
): void {
  useEffect(() => {
    if (!enabled) return;
    const element = ref.current;
    if (!element) return;
    const view = element.ownerDocument.defaultView ?? globalThis;
    const frame = view.requestAnimationFrame(() => {
      const el = ref.current;
      if (!el || el.contains(el.ownerDocument.activeElement)) return;
      const target = getFirstFocusableElement(el);
      const focusTarget = target ?? (fallbackToContainer ? el : null);
      focusTarget?.focus({ preventScroll: true });
    });
    return () => view.cancelAnimationFrame(frame);
  }, [ref, enabled, fallbackToContainer]);
}
